import axios from 'axios';
import Cookie from 'cookie-universal';

// ===== الإعدادات الأساسية =====
export const baseUrl = 'http://127.0.0.1:8000/api';

const cookie = Cookie();

// ===== إنشاء Axios Instance =====
const Axios = axios.create({
    baseURL: baseUrl,
    headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'X-Requested-With': 'XMLHttpRequest'
    }
});

// ===== Interceptor: إضافة Token تلقائياً =====
Axios.interceptors.request.use(
    (config) => {
        const token = cookie.get('educational-token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// ===== Interceptor: معالجة الأخطاء =====
Axios.interceptors.response.use(
    (response) => response,
    (error) => {
        if (error.response?.status === 419) {
            console.error('CSRF Token Error - تم تجاهله');
            // إعادة المحاولة بدون CSRF
            const config = error.config;
            return axios(config);
        }
        return Promise.reject(error);
    }
);

// ===== تصدير Axios =====
export default Axios;

// ===== روابط الـ API (Endpoints) =====

// Authentication
export const REGISTER = 'register';
export const LOGIN = 'login';
export const LOGOUT = 'logout';
export const USER = 'user';

// Courses
export const COURSES = 'courses';
export const COURSES_FEATURED = 'courses/featured';
export const COURSE_BY_ID = 'courses';

// Admin
export const ADMIN_COURSES = 'admin/courses';
